import cv2
import time
from ultralytics import YOLO
import rclpy
from rclpy.node import Node
from cv_bridge import CvBridge, CvBridgeError
from sensor_msgs.msg import Image
from deep_sort_realtime.deepsort_tracker import DeepSort



class Inventory_System(Node):

    def __init__(self):
        super().__init__('inventory_system')
        self.subscription = self.create_subscription(Image, '/video_frames', self.image_callback, 10)

        # Initialize YOLOv8 model, which over here is a pre-trained nano version
        self.model = YOLO('yolov8n.pt')
        self.bridge = CvBridge()

        #the deepsort tracker, age corresponds to max frames 
        #the tracker will keep a lost object
        #n_init is how many detections of an object before tracking enabled
        #both set to default values
        self.tracker = DeepSort(max_age=30, n_init=3)

        #list of items
        self.detected_items = []

        #inventory system counter
        self.inventory_detected_items = {}

    def image_callback(self, msg):
        #conversion of ROS to OpenCV
        frame = self.bridge.imgmsg_to_cv2(msg, "bgr8")

        #fps counter
        frame_count = 0
        start_time = time.time()


            #FPS counting
            #frame_count += 1
            #if curr_time > 0:
               # current_fps = frame_count / curr_time
                #print(f"FPS now is: {current_fps:.2f}")  
            #YOLOV8 DETECTION
            
            #performs the object detection on frame
        results = self.model(frame)

        #preps detection data for DeepSORT (format: [x1, y1, w, h, confidence])
        #note: specific format needed
        #detections is a list for detections for DeepSORTa for curr frame
        detections = []
        for result in results:
            for box in result.boxes:
                class_id = int(box.cls)
                confidence = float(box.conf)  # Ensure confidence is a float
                
                #extract x1, y1, x2, y2 and convert to integers
                #tensor to int for specific format
                x1, y1, x2, y2 = map(int, box.xyxy[0].tolist())
                width = x2 - x1
                height = y2 - y1

                #appends detections in the specified deepsort format [x1, y1, w, h, confidence]
                detections.append([[x1, y1, width, height], confidence, class_id])

        
        #DEEPSORT TRACKING

        #checks if there are any detections
        if detections:
            #update the DeepSORT tracker with detections and frame
            tracked_objects = self.tracker.update_tracks(detections, frame=frame)

            #checks if tracker is running
            if tracked_objects:
                print(f"Tracker is running :O, found {len(tracked_objects)} tracked objects.")
            else:
                print("No objects are being tracked.")

            #draws the bounding boxes and tracking IDs
            for track in tracked_objects:
                if not track.is_confirmed(): #detected consistently
                    continue

                track_id = track.track_id
                ltrb = track.to_ltrb()  #left top right bottom
                class_id = track.det_class  #class name from the detection

                #debugging print to check if tracking IDs are assigned
                #print(f"Tracked object: ID {track_id}, Coordinates: {ltrb}")

                class_name = self.model.names[class_id]
                
                #inventory system counting if new track ID is found
                if class_name not in self.inventory_detected_items:
                        self.inventory_detected_items[class_name] = set()
                if track_id not in self.inventory_detected_items[class_name]:
                    self.inventory_detected_items[class_name].add(track_id)
                
                #draws bounding boxes and track ID
                cv2.rectangle(frame, (int(ltrb[0]), int(ltrb[1])), (int(ltrb[2]), int(ltrb[3])), (0, 255, 0), 2)
                cv2.putText(frame, f"ID {track_id} - {class_name}", (int(ltrb[0]), int(ltrb[1]) - 10), cv2.FONT_HERSHEY_SIMPLEX, 0.6, (255, 0, 0), 2)

        #shows the video with detection n tracking
        cv2.imshow("YOLOv8 with DeepSORT Tracking", frame)

        #exit if 'q' is pressed, had to specifically be one key
        if cv2.waitKey(1) & 0xFF == ord('q'):
            rclpy.shutdown()


def main(args=None):
    rclpy.init(args=args)
    node = Inventory_System()
    try:
        rclpy.spin(node)
    except KeyboardInterrupt:
        cv2.destroyAllWindows()
        rclpy.shutdown()
    finally:
        #print final list of detected items
        print("\nFinal List of Detected Items:")
        for item in node.detected_items:
            print(item)

        # rint the inventory system (object counts)
        print("\nInventory System:")
        for class_name, ID in node.inventory_detected_items.items():
            #print(f"{class_name}: {ID}")
            print(f"{class_name}: {len(node.inventory_detected_items[class_name])} unique objects")

